    53→HeadersToAddEntry::HeadersToAddEntry(const HeaderValueOption& header_value_option,
    54→                                     absl::Status& creation_status)
    55→    : original_value_(header_value_option.header().value()),
    56→      add_if_empty_(header_value_option.keep_empty_value()) {
    57→
    58→  if (header_value_option.has_append()) {
    59→    // 'append' is set and ensure the 'append_action' value is equal to the default value.
    60→    if (header_value_option.append_action() != HeaderValueOption::APPEND_IF_EXISTS_OR_ADD) {
    61→      creation_status =
    62→          absl::InvalidArgumentError("Both append and append_action are set and it's not allowed");
    63→      return;
    64→    }
    65→
    66→    append_action_ = header_value_option.append().value()
    67→                         ? HeaderValueOption::APPEND_IF_EXISTS_OR_ADD
    68→                         : HeaderValueOption::OVERWRITE_IF_EXISTS_OR_ADD;
    69→  } else {
    70→    append_action_ = header_value_option.append_action();
    71→  }
    72→
    73→  auto formatter_or_error = parseHttpHeaderFormatter(header_value_option.header());
    74→  SET_AND_RETURN_IF_NOT_OK(formatter_or_error.status(), creation_status);
    75→  formatter_ = std::move(formatter_or_error.value());
    76→}
